package eu.gridverse.mock.srv.rsa.services;
import eu.gridverse.data.cnm.result.*; import java.util.*; import org.springframework.boot.SpringApplication; import org.springframework.boot.autoconfigure.SpringBootApplication; import org.springframework.web.bind.annotation.*;
@SpringBootApplication public class MockRsaServicesApplication { public static void main(String[] args) { SpringApplication.run(MockRsaServicesApplication.class, args); } @RestController @RequestMapping("/api/v1/rsa/workflows") static class Api { @PostMapping("/comparison") ResultVisualizationData compare(@RequestBody ResultVisualizationRequest r) { return new ResultVisualizationData(r.workflowId(), r.before(), r.after(), r.before().keySet().stream().filter(k -> Math.abs(r.after().getOrDefault(k,0d)) < Math.abs(r.before().get(k))).sorted().toList(), r.before().keySet().stream().filter(k -> Math.abs(r.after().getOrDefault(k,0d)) > Math.abs(r.before().get(k))).sorted().toList()); } } }
